head.script:
scwin.strFromDate = $c.date.getServerDateTime("yyyyMM")+"01";
scwin.strToDate = $c.date.getServerDateTime("yyyyMMdd");// 현재일자를 구한다.
scwin.memJson = $c.data.getMemInfo();
scwin.privAdmin = $c.data.getMemInfo("privAdmin");
scwin.isStarted = true;  // 최초 이벤트 여부 (자회사 구분 로직을 최초 한번만 처리)

scwin.vUserHomeClsCd = $c.data.getMemInfo("userHomeClsCd");// 사용자소속구분코드 
scwin.loginCoCd = $c.data.getMemInfo("coCd");
scwin.vLoginCoCd = $c.gus.cfIsNull(scwin.loginCoCd)?'':scwin.loginCoCd; // 소속 자회사
scwin.loginCoClsCd = $c.data.getMemInfo("coClsCd");
scwin.vLoginCoClsCd =$c.gus.cfIsNull(scwin.loginCoClsCd)?'': scwin.loginCoClsCd;  ;//회계_회사구분('CO035' : 0:동부 EXPRESS)

//-------------------------------------------------------------------------
// hidden
//-------------------------------------------------------------------------
scwin.txtCoClsCd ="";

//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    //ASIS 히든,showfalse 그리드 필드정보
    /*gr_acctRecvList.setColumnVisible("acctDeptCd", false);
    gr_acctRecvList.setColumnVisible("drawEmpNm", false);
    gr_acctRecvList.setColumnVisible("dispClntNm", false);
