    gr_acctRecvList.setColumnVisible("coCd", false);
    gr_acctRecvList.setColumnVisible("coClsCd", false);

    //ASIS 히든,showfalse 그리드 필드정보
    gr_collMoneyCont.setColumnVisible("bankbookNo", false);
    gr_collMoneyCont.setColumnVisible("billRecvNo", false);
    gr_collMoneyCont.setColumnVisible("susRecvInitamtOutbrNo", false);
    gr_collMoneyCont.setColumnVisible("acctRecvNo", false);
    gr_collMoneyCont.setColumnVisible("billRecvMgntNo", false);
    gr_collMoneyCont.setColumnVisible("clntNo", false);
    gr_collMoneyCont.setColumnVisible("acctCd", false);
    gr_collMoneyCont.setColumnVisible("collMoneyNo", false);
    gr_collMoneyCont.setColumnVisible("drcrClsCd", false);
    gr_collMoneyCont.setColumnVisible("crcCd", false);
    gr_collMoneyCont.setColumnVisible("exchRt", false);
    */
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    acb_delYn.setSelectedIndex(0);
    ed_FromDate.setValue(scwin.strFromDate);
    ed_ToDate.setValue(scwin.strToDate);
    ed_cancelDt.setValue(scwin.strToDate);
    scwin.f_setCompanyInfo(); 
};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
};

//-------------------------------------------------------------------------
// 자회사 회계 시스템 추가에 따른 설정 
//-------------------------------------------------------------------------
scwin.f_setCompanyInfo = function() {
    try {
        //사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
        if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {  
            scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
            scwin.vLoginCoClsCd = ACConstants.CO_CLS_CD_DONGBU;
        }
        ed_coCd.setValue(scwin.vLoginCoCd);

        scwin.f_PopUpCompanyInfo('T');
    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 회사코드입력시
//-------------------------------------------------------------------------
scwin.udc_coCd_onblurCodeEvent = function (e) {
    scwin.isStarted = false;
    ed_coNm.setValue("");
    scwin.f_PopUpCompanyInfo('T');
};

//-------------------------------------------------------------------------
// 회사코드 찾기버튼 클릭시
//-------------------------------------------------------------------------
scwin.udc_coCd_onclickEvent = function (e) {
    scwin.isStarted = false;
    scwin.f_PopUpCompanyInfo('F');
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 
//-------------------------------------------------------------------------
scwin.f_PopUpCompanyInfo = async function (pWinCloseTF) {

    /*
     var rtnList = cfCommonPopUp("retrieveDongbuGroupCompanyInfo"
								,ed_coCd.text, txt_coNm.value
								,pWinCloseTF,null,null,null,null
								,null,null,null,null,null);
    */
    udc_coCd.setSelectId('retrieveDongbuGroupCompanyInfo');
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_callBackFunc // 콜백 함수
                        , ed_coCd.getValue()              // 화면에서의 ??? Code Element의 Value
                        , ed_coNm.getValue()              // 화면에서의 ??? Name Element의 Value
                        , pWinCloseTF                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , null                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
};

//-------------------------------------------------------------------------
// 회사 입력 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_coCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // SET	 
        if(rtnList != null ) { 
            if (rtnList[0] == "N/A") return false;  
                ed_coCd.setValue(rtnList[0]);	// 코드
                ed_coNm.setValue(rtnList[5]);	// 회사명
                ed_coCd.hidVal = rtnList[0];  // 히든값
                scwin.txtCoClsCd = rtnList[1];	// 회사구분  
        }else{
            ed_coCd.setValue("");
            ed_coNm.setValue("");
            scwin.txtCoClsCd ="";
            scwin.txtCoClsCd = "";
        }

        if(scwin.txtCoClsCd > '0')  {  	// 자회사 회계 시스템 
            scwin.isSubCompany = true;
        }else{
            scwin.isSubCompany = false;
        }

        if ( scwin.isStarted == true ) {
            if('T' == scwin.privAdmin  ||  !scwin.isSubCompany   ) { // ADMIN 권한이 있는 경우, 동부 EXPRESS 인 경우 
                $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);    
            }else {
                $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company  ]);   
            }
        }

        ed_FromDate.focus();

    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    try{
        if (!$c.gus.cfIsAfterDate(ed_FromDate.getValue(),ed_ToDate.getValue())) {
            $c.gus.cfAlertMsg("조회 대손일자는종료일자보다 이전 날짜 이어야 합니다.");
            ed_FromDate.focus();
            return false;;
        }

        // 저장시 필수 입력 사항 Check
        let ret = await $c.gus.cfValidate([ed_FromDate,ed_ToDate]);
        if (!ret) {
            return false;
        }

        let ret2 = await $c.gus.cfValidate([ed_coCd]);
        if (!ret2) {
            return false;
        }
        ds_acctRecvList.removeAll();//데이터초기화
        ds_searchAcctRecvBdebt.set("acctRecvStsCd", ACConstants.COLLECION_OF_MONEY_BDEBT)
        $c.sbm.execute(sbm_searchAcctRecvBdebt);
    } catch (e) {
       console.log("f_Retrieve " + e);
    }
};

//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_searchAcctRecvBdebt_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        tbx_totalRows.setValue($c.gus.cfInsertComma(ds_acctRecvList.getRowCount()));
        if( ds_acctRecvList.getRowCount() == 0 ){
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        }else{
            ds_acctRecvList.setRowPosition(0);
            $c.gus.cfGoPrevPosition(gr_acctRecvList, 0);

            // 수금정산내역을 불러온다.
            ds_acctRecvCont_condition.set("collectionOfMoneyNumber", ds_acctRecvList.getCellData(0, "collMoneyNo"))
            sbm_acctRecvCont.action = "/ac.fm.acctrecvmgnt.acctrecvcontmgnt.RetrieveAccountReceivableBadDebtContentsCMD.do";
            $c.sbm.execute(sbm_acctRecvCont);  
        }
    } catch (e) {
       console.log("sbm_searchAcctRecvBdebt_submitdone " + e);
    }
};

//-------------------------------------------------------------------------
// 수금정산내역을 조회 콜백
//-------------------------------------------------------------------------
scwin.sbm_acctRecvCont_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        ds_acctRecvCont.setJSON(e.responseJSON.GAUCE);
        tbx_totalRows2.setValue($c.gus.cfInsertComma(ds_acctRecvCont.getRowCount()));
        $c.gus.cfGoPrevPosition(gr_collMoneyCont, 0);
    } catch (e) {
       console.log("sbm_acctRecvCont_submitdone : " + e);
    }
}; 

//-------------------------------------------------------------------------
//수금헤더 클릭시 수금정산내역을 조회 한다.
//-------------------------------------------------------------------------
scwin.gr_acctRecvList_oncellclick = function (rowIndex, columnIndex, columnId) {
    try{
        if (columnId != "num") {
            // 수금정산내역을 불러온다.
            ds_acctRecvCont_condition.set("collectionOfMoneyNumber", ds_acctRecvList.getCellData(rowIndex, "collMoneyNo"))
            sbm_acctRecvCont.action = "/ac.fm.acctrecvmgnt.acctrecvcontmgnt.RetrieveAccountReceivableBadDebtContentsCMD.do";
            $c.sbm.execute(sbm_acctRecvCont);
        }

        // 수금전표 POPUP
        if (columnId == "collMoneySlipNo") {
            $c.gus.cfShowSlipInfo(ds_acctRecvList.getCellData(rowIndex, "collMoneySlipNo"));
        }

        // 취소전표 POPUP
        if (columnId == "cnclSlipNo") {
            if (ds_acctRecvList.getCellData(rowIndex, "cnclSlipNo") != "") {
                $c.gus.cfShowSlipInfo(ds_acctRecvList.getCellData(rowIndex, "cnclSlipNo"));
            }
        }
    } catch (e) {
       console.log("gr_acctRecvList_oncellclick : " + e);
    }
}; 

//-------------------------------------------------------------------------
//그리드 삭제여부 데이터포맷처리
//-------------------------------------------------------------------------
scwin.delYnData=function(data){
    return $c.gus.decode(data,"1","예","아니오");
};

//-------------------------------------------------------------------------
// 귀속부서
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','CD');
};

//-------------------------------------------------------------------------
// 귀속부서명
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','NM');
};

//-------------------------------------------------------------------------
// 귀속부서찾기
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sacctDeptCd,ed_sacctDeptNm,'1','ALL');
};

//-------------------------------------------------------------------------
// 거래처
//-------------------------------------------------------------------------
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.f_CheckPopUp(ed_sclntNo,ed_sclntNm,'2','CD');
};

//-------------------------------------------------------------------------
// 거래처명
//-------------------------------------------------------------------------
scwin.udc_clntNo_onblurNameEvent = function (e) {
    scwin.f_CheckPopUp(ed_sclntNo,ed_sclntNm ,'2','NM');
};

//-------------------------------------------------------------------------
// 거래처찾기
//-------------------------------------------------------------------------
scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.f_openPopUp(ed_sclntNo,ed_sclntNm,'2','ALL');
};

//-------------------------------------------------------------------------
// PopUp창에서 사용되는 각 Cd,Nm에 대해서 POPUP표시 및 해당 값이 없을경우는 코드와 이름을 초기화 시킨다.
// flag값이 CD:코드변경이 없으면 POPUP안뛰움, NM:무조건 POPUP뛰움
//-------------------------------------------------------------------------
scwin.f_CheckPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
    try {
        if ( flag == "CD") {
            if (orgObjCd.getValue() == orgObjCd.hidVal) {
                return;
            } else {
                orgObjNm.setValue("");
            }
        }else {
            if (orgObjNm.getValue() == orgObjNm.hidVal) {
                return;
            } else {
                orgObjCd.setValue("");
            }
        }

        if (orgObjCd.getValue().trim() != "" || flag == "NM") {
		    if (orgObjNm.getValue().trim() != "" || flag == "CD") {   
                orgObjCd.setValue(orgObjCd.getValue().trim());
			    orgObjNm.setValue(orgObjNm.getValue().trim());
                scwin.f_openPopUp(orgObjCd, orgObjNm, select_code,"NO");
            }
        }else{
            orgObjNm.setValue("");
            orgObjCd.setValue("");
            orgObjCd.hidVal = "";
        }
    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->수금부서, 2:조회->대손사원, 3:조회->통장번호
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = async function (orgObjCd, orgObjNm, select_code, flag) {
    try {
        let cd = "";
        let nm = "";
        let param = "";

        // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
	    // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
        if (flag == "ALL") {
            cd = "";
            nm = "";
        } else {
            cd = orgObjCd.getValue();
            nm = orgObjNm.getValue();
        }

        switch (select_code) {
            // 조회조건용 수금부서 PopUp 호출
            case '1' :
                param  = ","+ ed_coCd.getValue()+","+scwin.txtCoClsCd;
                //rtnList = cfCommonPopUp('retrieveAcctDeptCdInfo6',cd, nm,"T",null,null,null,null,param,null,null,null,null); // 귀속부서
                udc_acctDeptCd.setSelectId('retrieveAcctDeptCdInfo6');
                udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_callBackFunc // 콜백 함수
                        , cd                              // 화면에서의 ??? Code Element의 Value
                        , nm                              // 화면에서의 ??? Name Element의 Value
                        , 'T'                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
                break;
            // 조회조건용 관리부서 PopUp 호출
            case '2' :
               param  = ",,,,"+ ed_coCd.getValue();
                //rtnList = cfCommonPopUp('retrieveClntList',cd,nm,"T",null,null,null,null,param,null,null,null,null); // 거래처
                udc_clntNo.setSelectId('retrieveClntList');
                udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                        , cd                              // 화면에서의 ??? Code Element의 Value
                        , nm                              // 화면에서의 ??? Name Element의 Value
                        , 'T'                             // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , param                           // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        ); 
                break;

            default :
                $c.gus.cfAlertMsg("잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
                break;            
        }
    } catch (e) {
       console.log("f_openPopUp : " +e);
    }
};

//-------------------------------------------------------------------------
// 부서 팝업 콜백(1)
//-------------------------------------------------------------------------
scwin.udc_acctDeptCd_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_sacctDeptCd.setValue(rtnList[0]);	// 코드값
			ed_sacctDeptNm.setValue(rtnList[1]);	// 코드명
            ed_sacctDeptCd.hidVal = rtnList[0];	// HIDDEN 코드값
            ed_sacctDeptNm.hidVal = rtnList[0];	// HIDDEN 코드값
		} else {
			ed_sacctDeptCd.setValue("");
			ed_sacctDeptNm.setValue("");
            ed_sacctDeptCd.hidVal = "";
            ed_sacctDeptNm.hidVal = "";
		}
    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 거래처 팝업 콜백(2)
//-------------------------------------------------------------------------
scwin.udc_clntNo_callBackFunc = function (ret) {
    try{
        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if (rtnList != null ) {
			if ( rtnList[0] == "N/A" ) return ;
			ed_clntNo.setValue(rtnList[0]);	// 코드값
			ed_clntNm.setValue(rtnList[1]);	// 코드명
            ed_clntNo.hidVal = rtnList[0];	// HIDDEN 코드값
            ed_clntNm.hidVal = rtnList[0];	// HIDDEN 코드값
		} else {
			ed_clntNo.setValue("");
			ed_clntNm.setValue("");
            ed_clntNo.hidVal = "";
            ed_clntNm.hidVal = "";
		}
    } catch (e) {
       console.log(e);
    }
};

//-------------------------------------------------------------------------
// 대손취소 함수 호출
//-------------------------------------------------------------------------
scwin.f_Cancel = async function () {
    try{
        if(ds_acctRecvList.getModifiedIndex().length==0){
            $c.gus.cfAlertMsg("선택하신 사항이 없습니다.");
            return false;
        }

        let ret = await $c.gus.cfValidate([ed_cancelDt]);
        if (!ret) {
            return false;
        }

        let count = 1;
        for (let i=0; i < ds_acctRecvList.getRowCount(); i++ ){
            count = count+ i;
            if (ds_acctRecvList.getCellData(i, "num") == "T") {
                if (ds_acctRecvList.getCellData(i,"cnclSlipNo") != "") {
                    $c.gus.cfAlertMsg(count+"행의 수금사항은 대손취소 하실수 없는 상태 입니다.");
                    ds_acctRecvList.setRowPosition(i);
                    return false;
                }
                if (ds_acctRecvList.getCellData(i,"delYn") == "1") {
                    $c.gus.cfAlertMsg(count+"행의 수금사항은 이미 삭제처리되었습니다. 확인하시기 바랍니다.");
                    ds_acctRecvList.setRowPosition(i);
                    return false;
                }
            }
        }

        if(await $c.win.confirm("선택하신 사항을 대손취소 하시겠습니까")) {
            for (let i=0; i < ds_acctRecvList.getRowCount(); i++ ){
                if (ds_acctRecvList.getCellData(i, "num") == "T") {
                    // 취소일자를 각 Row에 입력한다.
                    ds_acctRecvList.setCellData(i, "cnclDt", ed_cancelDt.getValue());
                }
            }
            sbm_saveAcctRecvBdebt.action = "/ac.fm.acctrecvmgnt.acctrecvcontmgnt.CancelAccountReceivableBadDebtCMD.do";

            ds_addAcctRecvBdebt.insertRow(0);
            ds_addAcctRecvBdebt.setArray("queryDeptSearchStDate", ed_FromDate.getValue());
            ds_addAcctRecvBdebt.setArray("queryDeptSearchEndDate", ed_ToDate.getValue());
            $c.sbm.execute(sbm_saveAcctRecvBdebt);
        }

    }catch (e) {
       console.log("f_Cancel : " + e);
    }
};

//-------------------------------------------------------------------------
// 대손취소 함수 호출 콜백
//-------------------------------------------------------------------------
scwin.sbm_saveAcctRecvBdebt_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0){
            //ds_acctRecvList.UndoAll();
            for (let i=0; i < ds_acctRecvList.getRowCount(); i++ ){
                ds_acctRecvList.undoRow(i);
            }
            return; //onFail
        }
        scwin.f_Retrieve();
        // 등록 화면에 대한 재조회
	  	if($p.parent().tabControl1.getWindow(0).ed_sclntNo.getValue() != "" && parent.iFrame0.ed_sacctDeptCd.getValue() != "" ) {
            $p.parent().tabControl1.getWindow(0).scwin.f_Retrieve();
        }
    } catch (e) {
       console.log("sbm_saveAcctRecvBdebt_submitdone : " + e);
    }
};

//-------------------------------------------------------------------------
// 엑셀 Download
//-------------------------------------------------------------------------
scwin.f_Export = function() {

    if ( ds_acctRecvList.getRowCount() <= 0)
    {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return false;
    }
    let sheetTitle;
    sheetTitle = "대손목록";
    const options = {
        fileName : sheetTitle +"xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: sheetTitle,   //엑셀내시트명지정필요시
        startRowIndex : 1,
        startColumnIndex : 0
    };

    //그리드에 대한 내용을 추가 옵션
    let infoArr = [
        //제목
        {
            rowIndex: 0               //제목을 표시할 행 index
            , colIndex: 0               //제목을 표시할 열 index
            , rowSpan: 1                //병합할 행의 수
            , colSpan: 11               //병합할 열의 수
            , text: sheetTitle          //표시할 내용(제목)
            , fontName: "돋움체"         //폰트이름 
            , fontSize: "18px"          //폰트 size
            , color :"black"            //폰트 color
            , textAlign: "center"       //표시할 내용의 정렬 방법(left, center, right)
            , bgColor : "#ffffff"       //배경 color
        }
    ];
    $c.data.downloadGridViewExcel(gr_acctRecvList, options, infoArr);
};

